mapper.select:
SELECT DISTINCT tsr.* FROM t_sys_resource tsr JOIN t_role_resource_link trrl ON tsr.resource_id = trrl.resource_id AND trrl.is_deleted = 0 AND trrl.status = 1 JOIN ( -- 查询用户和角色关联的角色 ID SELECT trul.role_id FROM t_role_user_link trul JOIN t_sys_role tsr ON trul.role_id = tsr.role_id AND tsr.is_deleted = 0 AND tsr.status = 1 WHERE trul.is_deleted = 0 AND trul.status = 1 AND trul.user_id = #{userId} UNION -- 查询用户所在用户组关联角色的角色 ID SELECT trugl.role_id FROM t_role_user_group_link trugl JOIN t_user_group_user_link tugul ON trugl.user_group_id = tugul.user_group_id AND trugl.is_deleted = 0 AND trugl.status = 1 AND tugul.is_deleted = 0 AND tugul.status = 1 JOIN t_sys_role tsr ON trugl.role_id = tsr.role_id AND tsr.is_deleted = 0 AND tsr.status = 1 JOIN t_sys_user_group tsug ON tugul.user_group_id = tsug.group_id AND tsug.is_deleted = 0 AND tsug.status = 1 WHERE tugul.user_id = #{userId} UNION -- 查询用户所在部门关联角色的角色 ID SELECT trdl.role_id FROM t_role_dept_link trdl JOIN t_sys_role tsr ON trdl.role_id = tsr.role_id AND trdl.is_deleted = 0 AND trdl.status = 1 AND tsr.is_deleted = 0 AND tsr.status = 1 WHERE EXISTS (SELECT 1 FROM t_sys_user tsu WHERE trdl.dept_id = tsu.dept_id AND tsu.is_deleted = 0 AND tsu.status = 1 AND tsu.user_id = #{userId}) ) AS all_roles ON trrl.role_id = all_roles.role_id WHERE tsr.is_deleted = 0 AND tsr.status = 1
AND tsr.resource_type IN ('M', 'C')
AND tsr.app_id = #{appId};
